const footerRuntime=()=>{var e=theme.footerStart;window.setTimeout(footerRuntime,1e3);const t=new Date(e),n=new Date;var e=(n.getTime()-t.getTime())/864e5,o=Math.floor(e),e=24*(e-o),r=Math.floor(e),m=60*(e-r),e=Math.floor(60*(e-r)),m=Math.floor(60*(m-e));const i=document.getElementById("runtime_days"),d=document.getElementById("runtime_hours"),u=document.getElementById("runtime_minutes"),a=document.getElementById("runtime_seconds");i&&(i.innerHTML=o),d&&(d.innerHTML=r),u&&(u.innerHTML=e),a&&(a.innerHTML=m)};window.addEventListener("DOMContentLoaded",footerRuntime);